import { useContext, useState, useEffect } from 'react';
import NotificationContext from '@/src/contexts/Nofitication.context';
import { notify } from '../helpers/notification.helpers';

interface NotificationHook {
  notificationElem: HTMLHuelNotificationElement | null;
  notify: (props: Parameters<typeof notify>[1]) => void;
}

const useNotification = (): NotificationHook => {
  const notificationElem = useContext(NotificationContext);
  const [element, setElement] = useState<HTMLHuelNotificationElement | null>(notificationElem);

  useEffect(() => {
    setElement(notificationElem);
  }, [notificationElem]);

  const notify = async (props: Parameters<typeof notify>[1]) => {
    if (!element) return;

    try {
      await notify(element, props);
    } catch (error) {
      console.error(error);
    }
  };

  return { notificationElem: element, notify };
};

export default useNotification;
```

