    def __init__(self):
        self.words = {}
        self.word_count = 0

    def add_word(self, word):
        if word not in self.words:
            self.words[word] = 0
        self.words[word] += 1
        self.word_count += 1

    def calculate_probability(self, word):
        return self.words[word] / self.word_count

    def train(self, text):
        words = text.split()
        for word in words:
            self.add_word(word)

    def perplexity(self, test_text):
        words = test_text.split()
        log_likelihood = 0
        for word in words:
            probability = self.calculate_probability(word)
            log_likelihood -= math.log2(probability)
        return 2 ** (log_likelihood / len(words))

